using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class ChargeAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ValidCharge_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task Charge_ReturnsUniqueChargeIds()
    {
        var r1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var r2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        Assert.AreNotEqual(r1.ChargeId, r2.ChargeId);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task NullCardToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync(null!, 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task EmptyCardToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync("", 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task WhitespaceCardToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync("   ", 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid", 0m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public async Task NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await _gateway.ChargeAsync("tok_valid", -5.00m);
    }

    [TestMethod]
    public async Task DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 25.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task MinimumValidAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task LargeAmount_Succeeds()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class RefundAsyncTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ValidRefund_ReturnsSuccessWithRefundId()
    {
        // Arrange – create a charge first
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);
        Assume.That(charge.Success, "Precondition: charge must succeed");

        // Act
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        // Assert
        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrEmpty(refund.RefundId));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task NullChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task EmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync("");
    }

    [TestMethod]
    public async Task InvalidChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task DoubleRefund_SecondReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);
        Assume.That(charge.Success);

        var first = await _gateway.RefundAsync(charge.ChargeId);
        Assume.That(first.Success);

        var second = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(second.Success);
    }
}

